#include<bits/stdc++.h>
using namespace std;
const int maxn = 500 + 10,maxm = 2000 + 10;
int n,m;
int cost[maxn],l[maxn];
int dp[maxn][maxm];

int main(){
    scanf("%d %d",&n,&m);
    memset(dp,0x3f,sizeof(dp));
    for(int i = 1;i <= n;i ++){
        scanf("%d %d",&cost[i],&l[i]);
    }
    for(int i = 0;i <= n;i ++){
        dp[i][0] = 0;
    }
    for(int i = 1;i <= n;i ++){
        for(int j = 1;j <= m;j ++){
            dp[i][j] = dp[i - 1][j];
            for(int k = 1;k <= l[i] && j - k >= 0;k ++){
                dp[i][j] = min(dp[i][j],dp[i - 1][j - k] + cost[i]);
            }
        }
    }
    if(dp[n][m] == 0x3f3f3f3f)  printf("no solution");
    else    printf("%d",dp[n][m]);
    return 0;
}
